 30→impl std::fmt::Display for SetupError {
 31→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 32→        match self {
 33→            Self::FileNotFound(path) => write!(f, "setup file not found: {path}"),
 34→            Self::CompilationFailed(msg) => write!(f, "setup compilation failed: {msg}"),
 35→            Self::ExecutionFailed(msg) => write!(f, "setup execution failed: {msg}"),
