 49→/// Compile a Rust setup file to a temporary binary.
 50→/// Returns the path to the compiled binary.
 51→fn compile_setup_file(file_path: &Path) -> Result<std::path::PathBuf, SetupError> {
 52→    if !file_path.exists() {
 53→        return Err(SetupError::FileNotFound(
 54→            file_path.to_string_lossy().into_owned(),
 55→        ));
 56→    }
 57→
 58→    let out_dir = std::env::temp_dir().join(format!("shatter-setup-{}", std::process::id()));
 59→    std::fs::create_dir_all(&out_dir).map_err(|e| {
 60→        SetupError::CompilationFailed(format!("failed to create output directory: {e}"))
 61→    })?;
 62→
 63→    let stem = file_path
 64→        .file_stem()
 65→        .and_then(|s| s.to_str())
 66→        .unwrap_or("setup");
 67→    let binary_path = out_dir.join(stem);
 68→
 69→    let output = Command::new("rustc")
 70→        .arg(file_path)
 71→        .arg("-o")
 72→        .arg(&binary_path)
 73→        .output()
 74→        .map_err(|e| SetupError::CompilationFailed(format!("failed to invoke rustc: {e}")))?;
 75→
 76→    if !output.status.success() {
 77→        let stderr = String::from_utf8_lossy(&output.stderr);
 78→        return Err(SetupError::CompilationFailed(stderr.into_owned()));
 79→    }
 80→
 81→    Ok(binary_path)
 82→}
 83→
 84→/// Execute a compiled setup binary as a subprocess.
 85→/// Passes setup parameters as JSON on stdin, reads context JSON from stdout.
 86→fn run_setup_binary(
 87→    binary_path: &Path,
 88→    level: SetupLevel,
 89→    scope: &str,
 90→    parent_context: Option<&SetupContextStack>,
 91→) -> Result<SetupResult, SetupError> {
 92→    let input = serde_json::json!({
 93→        "level": level,
 94→        "scope": scope,
 95→        "parent_context": parent_context,
 96→    });
 97→    let input_json = serde_json::to_string(&input)
 98→        .map_err(|e| SetupError::ExecutionFailed(format!("failed to serialize input: {e}")))?;
 99→
100→    let mut child = Command::new(binary_path)
101→        .stdin(std::process::Stdio::piped())
102→        .stdout(std::process::Stdio::piped())
103→        .stderr(std::process::Stdio::piped())
104→        .spawn()
105→        .map_err(|e| SetupError::ExecutionFailed(format!("failed to spawn setup binary: {e}")))?;
106→
107→    if let Some(stdin) = child.stdin.take() {
108→        use std::io::Write;
109→        let mut stdin = stdin;
110→        let _ = stdin.write_all(input_json.as_bytes());
111→    }
112→
113→    let output = child
114→        .wait_with_output()
115→        .map_err(|e| SetupError::ExecutionFailed(format!("failed to wait for setup binary: {e}")))?;
116→
117→    if !output.status.success() {
118→        let stderr = String::from_utf8_lossy(&output.stderr);
119→        return Err(SetupError::ExecutionFailed(format!(
120→            "setup binary exited with {}: {}",
121→            output.status, stderr
122→        )));
123→    }
124→
125→    let stdout = String::from_utf8_lossy(&output.stdout);
126→    let context: serde_json::Value = serde_json::from_str(stdout.trim()).map_err(|e| {
127→        SetupError::InvalidOutput(format!("expected JSON on stdout, got: {e}"))
128→    })?;
129→
130→    Ok(SetupResult { context })
131→}
